<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
  body { font-family: sans-serif; padding: 20px; display: flex; flex-direction: column; align-items: center; }
  #spreadsheet {
    display: grid;
    grid-template-columns: 50px repeat(10, 60px);
    grid-template-rows: 30px repeat(10, 40px);
    gap: 1px;
    background: #ccc;
    border: 1px solid #999;
    min-width: 650px;
    min-height: 440px; /* Ensure > 400 */
  }
  .cell {
    background: white;
    display: flex;
    align-items: center;
    padding: 2px;
    font-size: 12px;
  }
  .header-col, .header-row {
    background: #f0f0f0;
    text-align: center;
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 1px solid #999;
  }
  input.cell-input {
    width: 100%;
    height: 100%;
    border: none;
    outline: none;
    padding: 2px;
    box-sizing: border-box;
    font-family: inherit;
    background: white;
  }
  input.cell-input:focus {
    background: #e8f4ff;
  }
  .controls { margin-top: 10px; width: 650px; display: flex; flex-direction: column; gap: 5px;}
  textarea#csv { width: 100%; height: 100px; margin-top: 5px; }
</style>
</head>
<body>

<div id="spreadsheet"></div>
<div class="controls">
  <button id="export">Export CSV</button>
  <textarea id="csv" readonly></textarea>
</div>

<script>
(function() {
    const ROWS = 10;
    const COLS = ['A','B','C','D','E','F','G','H','I','J'];

    // State
    const cells = {}; // id -> raw string
    const computed = {}; // id -> value (number/string/error)
    const evaluating = new Set(); // Stack for cycle detection

    // DOM Elements
    const gridEl = document.getElementById('spreadsheet');
    const exportBtn = document.getElementById('export');
    const csvArea = document.getElementById('csv');

    // Initialize Grid
    function initGrid() {
        // Corner Header (Empty)
        createCell(0, 0, '', 'header-col header-row');

        // Column Headers (A-J)
        for(let c=0; c<COLS.length; c++) {
            createCell(c+1, 0, COLS[c], 'header-col header-row');
        }

        // Rows and Inputs
        for(let r=1; r<=ROWS; r++) {
            // Row Header (1-10)
            createCell(0, r, r.toString(), 'header-col header-row');

            for(let c=0; c<COLS.length; c++) {
                const id = COLS[c] + r;
                createInput(id, r, c+1);
            }
        }
    }

    function createCell(col, row, text, cls) {
        const div = document.createElement('div');
        div.className = cls;
        div.textContent = text;
        gridEl.appendChild(div);
    }

    function createInput(id, r, c) {
        const input = document.createElement('input');
        input.type = 'text';
        input.id = `cell-${id}`;
        input.className = 'cell-input';

        // Event Listeners
        input.addEventListener('focus', onCellFocus);
        input.addEventListener('blur', onCellBlur);
        input.addEventListener('keydown', (e) => {
            if(e.key === 'Enter') e.target.blur();
        });

        gridEl.appendChild(input);
    }

    function onCellFocus(e) {
        const id = e.target.id.replace('cell-', '');
        // Show raw text for editing
        e.target.value = cells[id] || '';
    }

    function onCellBlur(e) {
        const id = e.target.id.replace('cell-', '');
        commitCell(id, e.target.value);
    }

    function commitCell(id, val) {
        if (cells[id] === val) return; // No change
        cells[id] = val;
        recalculate();
    }

    // Recalculation Engine
    function recalculate() {
        for(let r=1; r<=ROWS; r++) {
            for(let c=0; c<COLS.length; c++) {
                const id = COLS[c] + r;
                computeCell(id);
            }
        }
        updateUI();
    }

    function computeCell(id) {
        if (evaluating.has(id)) return '#CYCLE'; // Cycle detected

        evaluating.add(id);
        try {
            const raw = cells[id] || '';

            if (raw.startsWith('=')) {
                const expr = raw.substring(1);
                const val = evaluate(expr, id);
                computed[id] = formatValue(val);
            } else {
                // Plain text or number
                if (raw === '') {
                    computed[id] = 0;
                } else {
                    const num = parseFloat(raw);
                    if (!isNaN(num)) {
                        computed[id] = num;
                    } else {
                        computed[id] = raw; // Plain text
                    }
                }
            }
        } catch (e) {
            computed[id] = '#ERR';
        } finally {
            evaluating.delete(id);
        }
    }

    function formatValue(val) {
        if (val === '#CYCLE' || val === '#ERR') return val;
        return String(val);
    }

    // Parser & Evaluator
    function evaluate(expr, callerId) {
        const tokens = tokenize(expr);
        const parser = new Parser(tokens);
        return parser.parse();
    }

    function tokenize(str) {
        const tokens = [];
        let i = 0;
        while (i < str.length) {
            if (/\s/.test(str[i])) { i++; continue; }

            // Numbers
            if (/[0-9]/.test(str[i])) {
                let numStr = '';
                while (i < str.length && /[0-9.]/.test(str[i])) {
                    numStr += str[i++];
                }
                tokens.push({ type: 'NUM', val: parseFloat(numStr) });
                continue;
            }

            // Cell References [A-J][1-9] or [A-J]10
            if (/[A-J]/.test(str[i])) {
                let ref = str[i++];
                while (i < str.length && /[0-9]/.test(str[i])) {
                    ref += str[i++];
                }
                tokens.push({ type: 'REF', val: ref });
                continue;
            }

            // Operators & Parens
            if (str[i] === '+') { tokens.push({type:'OP', val:'+'}); i++; continue; }
            if (str[i] === '-') { tokens.push({type:'OP', val:'-'}); i++; continue; }
            if (str[i] === '*') { tokens.push({type:'OP', val:'*'}); i++; continue; }
            if (str[i] === '/') { tokens.push({type:'OP', val:'/'}); i++; continue; }
            if (str[i] === '(') { tokens.push({type:'LPAREN'}); i++; continue; }
            if (str[i] === ')') { tokens.push({type:'RPAREN'}); i++; continue; }

            throw new Error('Invalid char');
        }
        return tokens;
    }

    class Parser {
        constructor(tokens) { this.tokens = tokens; this.pos = 0; }

        parse() {
            const val = this.parseExpr();
            if (this.pos < this.tokens.length) throw new Error('Unexpected token');
            return val;
        }

        parseExpr() {
            let left = this.parseTerm();
            while (this.peekType() === 'OP' && (this.peekVal() === '+' || this.peekVal() === '-')) {
                const op = this.next().val;
                const right = this.parseTerm();
                if (op === '+') left = left + right;
                else left = left - right;
            }
            return left;
        }

        parseTerm() {
            let left = this.parseFactor();
            while (this.peekType() === 'OP' && (this.peekVal() === '*' || this.peekVal() === '/')) {
                const op = this.next().val;
                const right = this.parseFactor();
                if (op === '*') left = left * right;
                else {
                    if (right === 0) throw new Error('Div by zero');
                    left = left / right;
                }
            }
            return left;
        }

        parseFactor() {
            if (this.peekType() === 'OP') {
                const op = this.next().val;
                const val = this.parseFactor(); // Unary +/-
                return op === '-' ? -val : val;
            }
            if (this.peekType() === 'LPAREN') {
                this.next();
                const val = this.parseExpr();
                this.expect('RPAREN');
                return val;
            }
            if (this.peekType() === 'NUM') {
                return this.next().val;
            }
            if (this.peekType() === 'REF') {
                const refId = this.next().val;
                return resolveRef(refId);
            }
            throw new Error('Unexpected token');
        }

        peekType() { return this.tokens[this.pos] ? this.tokens[this.pos].type : null; }
        peekVal() { return this.tokens[this.pos] ? this.tokens[this.pos].val : null; }
        next() { return this.tokens[this.pos++]; }
        expect(type) {
            const t = this.next();
            if (t.type !== type) throw new Error('Expected ' + type);
            return t;
        }
    }

    function resolveRef(id) {
        // Check cycle in global evaluating set
        if (evaluating.has(id)) return '#CYCLE';

        const val = computed[id];
        if (val !== undefined) return val;

        // Compute it now
        return computeCell(id);
    }

    function updateUI() {
        for(let r=1; r<=ROWS; r++) {
            for(let c=0; c<COLS.length; c++) {
                const id = COLS[c] + r;
                const input = document.getElementById(`cell-${id}`);
                if (input && !document.activeElement.isSameNode(input)) {
                    input.value = computed[id];
                }
            }
        }
    }

    // Export CSV
    exportBtn.addEventListener('click', () => {
        let csv = '';
        for(let r=1; r<=ROWS; r++) {
            const row = [];
            for(let c=0; c<COLS.length; c++) {
                const id = COLS[c] + r;
                row.push(computed[id] !== undefined ? computed[id] : '');
            }
            csv += row.join(',');
            if (r < ROWS) csv += '\n';
        }
        csvArea.value = csv;
    });

    // API: window.sheet
    window.sheet = {
        set: function(id, val) {
            cells[id] = val;
            recalculate();
        },
        get: function(id) {
            return computed[id] !== undefined ? String(computed[id]) : '';
        },
        raw: function(id) {
            return cells[id] || '';
        }
    };

    // Init
    initGrid();
    recalculate();

})();
</script>
</body>
</html>
